// Read and parse the report file
const fs = require('fs');
const filePath = $input.first().json.path;
const fileName = filePath.split('/').pop();

// Only process node reports matching n[2-5]_*_batch*.md
const reportPattern = /^n(\d+)_(.+)_batch(\d+)\.md$/;
const match = fileName.match(reportPattern);

if (!match) {
  return [{ json: { skip: true, reason: 'Not a node report file', file: fileName } }];
}

const nodeNumber = parseInt(match[1]);
const taskName = match[2];
const batchNumber = parseInt(match[3]);

const content = fs.readFileSync(filePath, 'utf8');

// Parse status from report
let status = 'UNKNOWN';
const statusMatch = content.match(/##\s*Status:\s*(PASS|FAIL|PARTIAL|BLOCKED)/i);
if (statusMatch) {
  status = statusMatch[1].toUpperCase();
}

// Parse task ID
let taskId = 'UNKNOWN';
const taskIdMatch = content.match(/##\s*Task\s*ID:\s*(\S+)/i);
if (taskIdMatch) {
  taskId = taskIdMatch[1];
}

// Parse files changed
const filesChanged = [];
const filesSection = content.match(/### CHANGES MADE[\s\S]*?(?=###|$)/i);
if (filesSection) {
  const fileMatches = filesSection[0].match(/- \[?([^\]\n]+?)\]?:?\s/g);
  if (fileMatches) {
    fileMatches.forEach(m => {
      const f = m.replace(/^- \[?/, '').replace(/\]?:?\s*$/, '').trim();
      if (f) filesChanged.push(f);
    });
  }
}

// Parse cross-stream alerts
const crossStreamAlerts = [];
const alertsSection = content.match(/### CROSS-STREAM ALERTS[\s\S]*?(?=###|$)/i);
if (alertsSection) {
  const alertLines = alertsSection[0].split('\n').filter(l => l.startsWith('- '));
  alertLines.forEach(l => crossStreamAlerts.push(l.replace(/^- /, '')));
}

// Parse issues
const issues = [];
const issuesSection = content.match(/### NEW ISSUES FOUND[\s\S]*?(?=###|$)/i);
if (issuesSection) {
  const issueLines = issuesSection[0].split('\n').filter(l => l.startsWith('- '));
  issueLines.forEach(l => issues.push(l.replace(/^- /, '')));
}

return [{
  json: {
    skip: false,
    file_path: filePath,
    file_name: fileName,
    node_number: nodeNumber,
    task_name: taskName,
    batch_number: batchNumber,
    task_id: taskId,
    status: status,
    files_changed: filesChanged,
    cross_stream_alerts: crossStreamAlerts,
    issues: issues,
    report_content: content,
    parsed_at: new Date().toISOString()
  }
}];

// Determine next task in the delegation chain
const fs = require('fs');
const data = $input.first().json;
const currentNode = data.node_number;
const batchNumber = data.batch_number;

// Delegation chain: Node 2 (schemas) -> Node 3 (research) -> Node 4 (code) -> Node 5 (workflows) -> Red Team
const chainOrder = [2, 3, 4, 5];
const currentIndex = chainOrder.indexOf(currentNode);

let nextAction = 'BATCH_COMPLETE';
let nextNode = null;
let nextTaskFile = null;

if (currentIndex >= 0 && currentIndex < chainOrder.length - 1) {
  nextNode = chainOrder[currentIndex + 1];
  nextAction = 'DISPATCH_NEXT';

  // Check if a task file exists for the next node
  const promptsDir = '/root/ai-agent-pipeline/prompts/';
  const expectedFile = `batch${batchNumber}_n${nextNode}_tasks.json`;
  nextTaskFile = promptsDir + expectedFile;

  // If the task file exists, read it; otherwise create dispatch signal
  if (fs.existsSync(nextTaskFile)) {
    nextAction = 'DISPATCH_NEXT';
  } else {
    nextAction = 'SIGNAL_ORCHESTRATOR';
  }
} else if (currentIndex === chainOrder.length - 1) {
  // Last node completed — trigger red team
  nextAction = 'TRIGGER_RED_TEAM';
}

return [{
  json: {
    ...data,
    next_action: nextAction,
    next_node: nextNode,
    next_task_file: nextTaskFile,
    delegation_chain_position: `${currentIndex + 1}/${chainOrder.length}`
  }
}];

