// STOP node — log that pipeline is halted
const data = $input.first().json;

return [{
  json: {
    action: 'PIPELINE_HALTED',
    reason: `Node ${data.node_number} failed with status: ${data.status}`,
    task_id: data.task_id,
    batch: data.batch_number,
    halted_at: new Date().toISOString(),
    requires: 'manual_review'
  }
}];
